export interface SortableListOptions {
  /** CSS selector to identify draggable items within the container. */
  itemSelector: string;
  /** CSS selector for the drag handle within each item. If null, the whole item is the handle. */
  handleSelector: string | null;
  /**
   * Returns the group identifier for an item element.
   * Items with the same group can be reordered within that group.
   * Return null for ungrouped items (flat list).
   */
  getGroupOf?: (item: HTMLElement) => string | null;
  /** Whether items can be dragged across group boundaries. Default: false. */
  allowCrossGroup?: boolean;
  /** Called continuously as the dragged item moves, with preview indices. */
  onPreview?: (fromIndex: number, toIndex: number) => void;
  /** Called when a drag completes and item position is committed. */
  onCommit?: (
    fromIndex: number,
    toIndex: number,
    fromGroup: string | null,
    toGroup: string | null,
  ) => void;
  /** Called when a drag is cancelled (Escape, invalid drop, etc.). */
  onCancel?: () => void;
  /** CSS class applied to the original item while dragging (placeholder). Default: 'o9ds-sortable--ghost'. */
  ghostClass?: string;
  /** CSS class applied to the cloned drag image. Default: 'o9ds-sortable--dragging'. */
  draggingClass?: string;
  /** CSS class for the drop line indicator above a target. Default: 'o9ds-sortable--drop-above'. */
  dropAboveClass?: string;
  /** CSS class for the drop line indicator below a target. Default: 'o9ds-sortable--drop-below'. */
  dropBelowClass?: string;
}

export interface SortableHandle {
  /** Clean up all listeners and DOM artifacts. */
  destroy: () => void;
  /** Whether a drag is currently in progress. */
  isDragging: () => boolean;
}

interface DragState {
  sourceItem: HTMLElement;
  sourceIndex: number;
  sourceGroup: string | null;
  clone: HTMLElement;
  currentIndex: number;
  currentGroup: string | null;
  startY: number;
  offsetY: number;
  liveRegion: HTMLElement;
  items: HTMLElement[];
}

function getItemIndex(items: HTMLElement[], el: HTMLElement): number {
  return items.indexOf(el);
}

function findClosestItem(
  items: HTMLElement[],
  y: number,
): { index: number; position: 'above' | 'below' } | null {
  for (let i = 0; i < items.length; i++) {
    const rect = items[i].getBoundingClientRect();
    const mid = rect.top + rect.height / 2;
    if (y < mid) return { index: i, position: 'above' };
  }
  if (items.length > 0) {
    return { index: items.length - 1, position: 'below' };
  }
  return null;
}

function getOrCreateLiveRegion(): HTMLElement {
  let region = document.getElementById('o9ds-sortable-live');
  if (!region) {
    region = document.createElement('div');
    region.id = 'o9ds-sortable-live';
    region.setAttribute('role', 'status');
    region.setAttribute('aria-live', 'polite');
    region.setAttribute('aria-atomic', 'true');
    Object.assign(region.style, {
      position: 'absolute',
      width: '1px',
      height: '1px',
      overflow: 'hidden',
      clip: 'rect(0 0 0 0)',
      whiteSpace: 'nowrap',
    });
    document.body.appendChild(region);
  }
  return region;
}

function announce(region: HTMLElement, message: string): void {
  region.textContent = '';
  requestAnimationFrame(() => {
    region.textContent = message;
  });
}

export function createSortableList(
  container: HTMLElement,
  options: SortableListOptions,
): SortableHandle {
  const {
    itemSelector,
    handleSelector,
    getGroupOf,
    allowCrossGroup = false,
    onPreview,
    onCommit,
    onCancel,
    ghostClass = 'o9ds-sortable--ghost',
    draggingClass = 'o9ds-sortable--dragging',
    dropAboveClass = 'o9ds-sortable--drop-above',
    dropBelowClass = 'o9ds-sortable--drop-below',
  } = options;

  let state: DragState | null = null;
  let destroyed = false;

  function getItems(): HTMLElement[] {
    return Array.from(container.querySelectorAll<HTMLElement>(itemSelector));
  }

  function getGroupItems(
    items: HTMLElement[],
    group: string | null,
  ): HTMLElement[] {
    if (!getGroupOf || group === null) return items;
    return items.filter((item) => getGroupOf(item) === group);
  }

  function clearDropIndicators(): void {
    const items = getItems();
    for (const item of items) {
      item.classList.remove(dropAboveClass, dropBelowClass);
    }
  }

  function startDrag(item: HTMLElement, clientY: number): void {
    if (state) return;

    const items = getItems();
    const index = getItemIndex(items, item);
    if (index === -1) return;

    const group = getGroupOf?.(item) ?? null;
    const rect = item.getBoundingClientRect();

    const clone = item.cloneNode(true) as HTMLElement;
    clone.classList.add(draggingClass);
    clone.removeAttribute('id');
    Object.assign(clone.style, {
      position: 'fixed',
      zIndex: '10000',
      width: `${rect.width}px`,
      height: `${rect.height}px`,
      left: `${rect.left}px`,
      top: `${rect.top}px`,
      pointerEvents: 'none',
      margin: '0',
      boxShadow: '0 4px 16px rgba(0,0,0,0.15)',
      opacity: '0.95',
    });
    document.body.appendChild(clone);

    item.classList.add(ghostClass);

    const liveRegion = getOrCreateLiveRegion();

    state = {
      sourceItem: item,
      sourceIndex: index,
      sourceGroup: group,
      clone,
      currentIndex: index,
      currentGroup: group,
      startY: clientY,
      offsetY: clientY - rect.top,
      liveRegion,
      items,
    };

    container.classList.add('is-dragging');

    document.addEventListener('pointermove', onPointerMove);
    document.addEventListener('pointerup', onPointerUp);
    document.addEventListener('pointercancel', onPointerCancel);
    document.addEventListener('keydown', onKeydownDuringDrag);
  }

  function moveDrag(clientY: number): void {
    if (!state) return;

    state.clone.style.top = `${clientY - state.offsetY}px`;

    clearDropIndicators();

    const target = findClosestItem(state.items, clientY);
    if (!target) return;

    const targetItem = state.items[target.index];
    const targetGroup = getGroupOf?.(targetItem) ?? null;

    if (!allowCrossGroup && getGroupOf && state.sourceGroup !== null) {
      if (targetGroup !== state.sourceGroup) return;
    }

    if (target.position === 'above') {
      targetItem.classList.add(dropAboveClass);
    } else {
      targetItem.classList.add(dropBelowClass);
    }

    const newIndex =
      target.position === 'above' ? target.index : target.index + 1;
    if (newIndex !== state.currentIndex || targetGroup !== state.currentGroup) {
      state.currentIndex = newIndex;
      state.currentGroup = targetGroup;
      onPreview?.(state.sourceIndex, newIndex);
    }
  }

  function commitDrag(): void {
    if (!state) return;

    const { sourceIndex, currentIndex, sourceGroup, currentGroup } = state;
    cleanupDrag();

    if (sourceIndex !== currentIndex || sourceGroup !== currentGroup) {
      const groupItems = getGroupItems(
        getItems(),
        currentGroup,
      );
      const totalInGroup = groupItems.length;
      const posInGroup =
        currentIndex > sourceIndex ? currentIndex : currentIndex + 1;
      announce(
        getOrCreateLiveRegion(),
        `Moved item to position ${posInGroup} of ${totalInGroup}`,
      );
      onCommit?.(sourceIndex, currentIndex, sourceGroup, currentGroup);
    }
  }

  function cancelDrag(): void {
    if (!state) return;
    cleanupDrag();
    onCancel?.();
  }

  function cleanupDrag(): void {
    if (!state) return;

    state.sourceItem.classList.remove(ghostClass);
    state.clone.remove();
    clearDropIndicators();
    container.classList.remove('is-dragging');

    document.removeEventListener('pointermove', onPointerMove);
    document.removeEventListener('pointerup', onPointerUp);
    document.removeEventListener('pointercancel', onPointerCancel);
    document.removeEventListener('keydown', onKeydownDuringDrag);

    state = null;
  }

  function onPointerDown(e: PointerEvent): void {
    if (destroyed) return;
    const target = e.target as HTMLElement;

    let handleEl: HTMLElement | null = null;
    if (handleSelector) {
      handleEl = target.closest<HTMLElement>(handleSelector);
      if (!handleEl) return;
    }

    const item = target.closest<HTMLElement>(itemSelector);
    if (!item || !container.contains(item)) return;

    e.preventDefault();
    (e.target as HTMLElement).setPointerCapture?.(e.pointerId);
    startDrag(item, e.clientY);
  }

  function onPointerMove(e: PointerEvent): void {
    moveDrag(e.clientY);
  }

  function onPointerUp(_e: PointerEvent): void {
    commitDrag();
  }

  function onPointerCancel(_e: PointerEvent): void {
    cancelDrag();
  }

  function onKeydownDuringDrag(e: KeyboardEvent): void {
    if (e.key === 'Escape') {
      e.preventDefault();
      cancelDrag();
    }
  }

  function onKeydownForReorder(e: KeyboardEvent): void {
    if (destroyed || state) return;
    if (!e.ctrlKey && !e.metaKey) return;
    if (e.key !== 'ArrowUp' && e.key !== 'ArrowDown') return;

    const target = e.target as HTMLElement;
    const handle = handleSelector
      ? target.closest<HTMLElement>(handleSelector)
      : null;
    if (handleSelector && !handle) return;

    const item = target.closest<HTMLElement>(itemSelector);
    if (!item || !container.contains(item)) return;

    e.preventDefault();
    const items = getItems();
    const index = getItemIndex(items, item);
    if (index === -1) return;

    const group = getGroupOf?.(item) ?? null;
    const direction = e.key === 'ArrowUp' ? -1 : 1;
    const newIndex = index + direction;
    if (newIndex < 0 || newIndex >= items.length) return;

    const targetItem = items[newIndex];
    const targetGroup = getGroupOf?.(targetItem) ?? null;

    if (!allowCrossGroup && getGroupOf && group !== null) {
      if (targetGroup !== group) return;
    }

    const groupItems = getGroupItems(items, targetGroup ?? group);
    const posInGroup = groupItems.indexOf(targetItem) + 1;
    announce(
      getOrCreateLiveRegion(),
      `Moved item ${direction === -1 ? 'up' : 'down'} to position ${posInGroup} of ${groupItems.length}`,
    );

    onCommit?.(index, newIndex, group, targetGroup);
  }

  container.addEventListener('pointerdown', onPointerDown);
  container.addEventListener('keydown', onKeydownForReorder);

  return {
    destroy() {
      destroyed = true;
      if (state) cancelDrag();
      container.removeEventListener('pointerdown', onPointerDown);
      container.removeEventListener('keydown', onKeydownForReorder);
    },
    isDragging() {
      return state !== null;
    },
  };
}
